A single skill bundled into the bot workspace. Source code in src/openenv/core/models.py @dataclass(slots=True) class SkillConfig: """A single skill bundled into the bot workspace.""" name: str description: str content: str | None = None source: str | None = None assets: dict[str, str] = field(default_factory=dict) def to_dict(self) -> dict[str, Any]: """Serialize the declarative skill definition as it should appear in the manifest.""" data: dict[str, Any] = { "assets": dict(sorted(self.assets.items())), "description": self.description, "name": self.name, } if self.content is not None: data["content"] = self.content if self.source is not None: data["source"] = self.source return data def rendered_content( self, *, state_dir: str | None = None, workspace: str | None = None, ) -> str: """Return the effective `SKILL.md` text, optionally rewritten for a target runtime. Referenced catalog skills are materialized into a placeholder `SKILL.md` so the build pipeline, scanners, and snapshots can treat inline and external skills uniformly. """ if self.content is not None: rendered = self.content else: source = self.source or "unknown" rendered = ( "---
" f"name: {self.name}
" f"description: {self.description}
" f"source: {source}
" "---

" "This skill is referenced from an external catalog.

" f"Suggested install command:
`clawhub install {source}`
" ) if state_dir is None or workspace is None: return rendered return rewrite_openclaw_home_paths( rendered, state_dir=state_dir, workspace=workspace, ) def snapshot( self, *, state_dir: str | None = None, workspace: str | None = None, ) -> dict[str, Any]: """Return a stable content hash snapshot of the rendered skill and its assets.""" return { "assets": { path: sha256_text( rewrite_openclaw_home_paths( content, state_dir=state_dir, workspace=workspace, ) if state_dir is not None and workspace is not None else content ) for path, content in sorted(self.assets.items()) }, "content_sha256": sha256_text( self.rendered_content(state_dir=state_dir, workspace=workspace) ), "description": self.description, "name": self.name, "source": self.source, }

